import { lauxlib, lua, lualib, to_jsstring } from 'fengari-web';

/**
 * Execute a string of Lua code and return any output.
 * Think of this like a tiny Lua "virtual machine" in your browser.
 */
function executeLua(code: string): string[] {
  const output: string[] = [];

  // Create a new Lua state (a fresh, empty environment)
  const L = lauxlib.luaL_newstate();
  lualib.luaL_openlibs(L);

  // Override Lua's print() to capture output instead of
  // sending it to the browser console
  lua.lua_pushcfunction(L, (luaState: any) => {
    const numArgs = lua.lua_gettop(luaState);
    const parts: string[] = [];
    for (let i = 1; i <= numArgs; i++) {
      parts.push(to_jsstring(
        lauxlib.luaL_tolstring(luaState, i, null)
      ));
      lua.lua_pop(luaState, 1);
    }
    output.push(parts.join('\t'));
    return 0;
  });
  lua.lua_setglobal(L, 'print');

  // Run the Lua code
  const status = lauxlib.luaL_dostring(L, code);

  if (status !== 0) {
    // If there was an error, capture the error message
    const errorMsg = to_jsstring(lua.lua_tostring(L, -1));
    output.push('Error: ' + errorMsg);
  }

  // Clean up
  lua.lua_close(L);

  return output;
}

