import { lauxlib, lua, lualib, to_luastring } from 'fengari-web';

function executeLuaWithContext(
  code: string,
  context: Record<string, string | number | boolean>
): string[] {
  const output: string[] = [];
  const L = lauxlib.luaL_newstate();
  lualib.luaL_openlibs(L);

  // Push each context value as a Lua global variable
  for (const [key, value] of Object.entries(context)) {
    if (typeof value === 'string') {
      lua.lua_pushstring(L, to_luastring(value));
    } else if (typeof value === 'number') {
      lua.lua_pushnumber(L, value);
    } else if (typeof value === 'boolean') {
      lua.lua_pushboolean(L, value ? 1 : 0);
    }
    lua.lua_setglobal(L, to_luastring(key));
  }

  lauxlib.luaL_dostring(L, to_luastring(code));
  lua.lua_close(L);
  return output;
}

