import { LuaFactory, LuaEngine } from 'wasmoon';

// Cache the factory so we only load the WASM binary once
let factoryInstance: LuaFactory | null = null;

async function getFactory(): Promise<LuaFactory> {
  if (!factoryInstance) {
    factoryInstance = new LuaFactory();
  }
  return factoryInstance;
}

/**
 * Run a Lua script and return the captured output lines.
 * Automatically creates and cleans up the Lua engine.
 */
export async function runLuaScript(
  code: string,
  globals?: Record<string, unknown>
): Promise<{ output: string[]; error: string | null }> {
  const factory = await getFactory();
  const lua = await factory.createEngine();
  const output: string[] = [];

  try {
    // Replace print() so we can capture output
    lua.global.set('print', (...args: unknown[]) => {
      output.push(args.map(String).join('\t'));
    });

    // Inject any global variables the script needs
    if (globals) {
      for (const [key, value] of Object.entries(globals)) {
        lua.global.set(key, value);
      }
    }

    // Execute the Lua code
    await lua.doString(code);

    return { output, error: null };
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    return { output, error: message };
  } finally {
    // Always clean up to avoid memory leaks
    lua.global.close();
  }
}

