// Lazy-load wasmoon so it does not slow down initial page load
let LuaFactory: any = null;

const DEFAULT_CODE = `-- Try writing some Lua code!
local function fibonacci(n)
  if n <= 1 then return n end
  return fibonacci(n - 1) + fibonacci(n - 2)
end

for i = 0, 10 do
