export default function LuaPlayground() {
  const [code, setCode] = useState(DEFAULT_CODE);
  const [output, setOutput] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [isRunning, setIsRunning] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const runCode = useCallback(async () => {
    setIsRunning(true);
    setError(null);
    const lines: string[] = [];

    try {
      // Load wasmoon on first run (lazy loading)
      if (!LuaFactory) {
        const wasmoon = await import('wasmoon');
        LuaFactory = wasmoon.LuaFactory;
      }

      const factory = new LuaFactory();
      const lua = await factory.createEngine();

      try {
        // Capture print output
        lua.global.set('print', (...args: any[]) => {
          lines.push(args.map(String).join('\t'));
        });

        // Set a timeout to prevent infinite loops
        const timeout = setTimeout(() => {
          lua.global.close();
        }, 5000);

        await lua.doString(code);
        clearTimeout(timeout);
        setOutput(lines);
      } finally {
        lua.global.close();
      }
    } catch (err: any) {
      setError(err.message || 'An unknown error occurred');
      setOutput(lines);
    } finally {
      setIsRunning(false);
    }
  }, [code]);

  return (
    <div style={{ border: '1px solid #e0e0e0', borderRadius: 8, overflow: 'hidden' }}>
      {/* Code editor area */}
      <div style={{ padding: 8, backgroundColor: '#f5f5f5', borderBottom: '1px solid #e0e0e0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontWeight: 600, fontSize: 14 }}>Lua Playground</span>
        <button
          onClick={runCode}
          disabled={isRunning}
          style={{ padding: '6px 16px', backgroundColor: '#1976d2', color: 'white', border: 'none', borderRadius: 4, cursor: isRunning ? 'not-allowed' : 'pointer' }}
        >
          {isRunning ? 'Running...' : 'Run Code'}
        </button>
      </div>

      <textarea
        ref={textareaRef}
        value={code}
        onChange={(e) => setCode(e.target.value)}
        spellCheck={false}
        style={{ width: '100%', minHeight: 200, padding: 12, fontFamily: 'monospace', fontSize: 14, border: 'none', outline: 'none', resize: 'vertical', backgroundColor: '#1e1e1e', color: '#d4d4d4' }}
      />

      {/* Output area */}
      <div style={{ padding: 12, backgroundColor: '#0d1117', color: '#58a6ff', fontFamily: 'monospace', fontSize: 13, minHeight: 60 }}>
        <div style={{ color: '#8b949e', marginBottom: 4 }}>Output:</div>
        {error && <div style={{ color: '#f85149' }}>{error}</div>}
        {output.map((line, i) => (
          <div key={i}>{line}</div>
        ))}
        {!error && output.length === 0 && (
          <div style={{ color: '#8b949e' }}>Click "Run Code" to see output</div>
        )}
      </div>
    </div>
  );
}

