interface GameState {
  playerHealth: number;
  playerScore: number;
  enemies: Array<{ name: string; health: number; x: number; y: number }>;
  items: Array<{ name: string; effect: string }>;
}

export async function createGameScriptEngine(initialState: GameState) {
  const factory = new LuaFactory();
  const lua = await factory.createEngine();

  // Expose game state to Lua
  lua.global.set('gameState', initialState);

  // Expose safe game actions that Lua can call
  lua.global.set('dealDamage', (target: string, amount: number) => {
    const enemy = initialState.enemies.find(e => e.name === target);
    if (enemy) {
      enemy.health = Math.max(0, enemy.health - amount);
      return true;
    }
    return false;
  });

  lua.global.set('addScore', (points: number) => {
    initialState.playerScore += points;
  });

  lua.global.set('healPlayer', (amount: number) => {
    initialState.playerHealth = Math.min(100, initialState.playerHealth + amount);
  });

  lua.global.set('spawnEnemy', (name: string, health: number, x: number, y: number) => {
    initialState.enemies.push({ name, health, x, y });
  });

  return {
    /** Run a Lua game script */
    async runScript(code: string) {
      await lua.doString(code);
    },

    /** Get current game state */
    getState(): GameState {
      return { ...initialState };
    },

    /** Clean up when done */
    destroy() {
      lua.global.close();
    }
  };
}

