import { LuaFactory } from 'wasmoon';

let factory: LuaFactory | null = null;

async function getFactory() {
  if (!factory) {
    factory = new LuaFactory();
  }
  return factory;
}

// Listen for messages from the main thread
self.addEventListener('message', async (event) => {
  const { id, code, globals } = event.data;
  const output: string[] = [];

  try {
    const f = await getFactory();
    const lua = await f.createEngine();

    try {
      lua.global.set('print', (...args: any[]) => {
        output.push(args.map(String).join('\t'));
      });

      if (globals) {
        for (const [key, value] of Object.entries(globals)) {
          lua.global.set(key, value);
        }
      }

      await lua.doString(code);

      // Send results back to the main thread
      self.postMessage({ id, output, error: null });
    } finally {
      lua.global.close();
    }
  } catch (err: any) {
    self.postMessage({ id, output, error: err.message });
  }
});

import { useRef, useCallback } from 'react';

interface LuaResult {
  output: string[];
  error: string | null;
}

/**
 * React hook that runs Lua scripts in a Web Worker.
 * Your UI stays responsive even if the Lua script takes a while.
 */
export function useLuaWorker() {
  const workerRef = useRef<Worker | null>(null);
  const callbacksRef = useRef<Map<string, (result: LuaResult) => void>>(
    new Map()
  );

  const getWorker = useCallback(() => {
    if (!workerRef.current) {
      workerRef.current = new Worker(
        new URL('../workers/lua-worker.ts', import.meta.url)
      );

      workerRef.current.addEventListener('message', (event) => {
        const { id, output, error } = event.data;
        const callback = callbacksRef.current.get(id);
        if (callback) {
          callback({ output, error });
          callbacksRef.current.delete(id);
        }
      });
    }
    return workerRef.current;
  }, []);

  const runLua = useCallback(
    (code: string, globals?: Record<string, unknown>): Promise<LuaResult> => {
      return new Promise((resolve) => {
        const id = crypto.randomUUID();
        callbacksRef.current.set(id, resolve);
        getWorker().postMessage({ id, code, globals });
      });
    },
    [getWorker]
  );

  return { runLua };
}

