import { LuaFactory, LuaEngine } from 'wasmoon';

/**
 * An engine pool that reuses Lua engines instead of creating new ones.
 * This avoids the startup cost of creating a fresh engine for each script.
 */
class LuaEnginePool {
  private factory: LuaFactory | null = null;
  private available: LuaEngine[] = [];
  private maxSize: number;

  constructor(maxSize = 3) {
    this.maxSize = maxSize;
  }

  private async getFactory(): Promise<LuaFactory> {
    if (!this.factory) {
      this.factory = new LuaFactory();
    }
    return this.factory;
  }

  async acquire(): Promise<LuaEngine> {
    // Reuse an existing engine if available
    const existing = this.available.pop();
    if (existing) return existing;

    // Otherwise create a new one
    const factory = await this.getFactory();
    return factory.createEngine();
  }

  release(engine: LuaEngine) {
    if (this.available.length < this.maxSize) {
      // Reset the engine state and return it to the pool
      // Note: you may want to clear globals here
      this.available.push(engine);
    } else {
      // Pool is full, just close this engine
      engine.global.close();
    }
  }

  destroy() {
    for (const engine of this.available) {
      engine.global.close();
    }
    this.available = [];
  }
}

// Usage
const pool = new LuaEnginePool(3);

async function runWithPool(code: string): Promise<string[]> {
  const engine = await pool.acquire();
  const output: string[] = [];

  try {
    engine.global.set('print', (...args: any[]) =>
      output.push(args.map(String).join('\t'))
    );
    await engine.doString(code);
    return output;
  } finally {
    pool.release(engine);
  }
}

import { LuaFactory } from 'wasmoon';

/**
 * Create a sandboxed Lua engine with dangerous functions removed.
 * Only the functions you explicitly allow will be available.
 */
export async function createSandboxedEngine() {
  const factory = new LuaFactory();
  const lua = await factory.createEngine();

  // Remove potentially dangerous standard library functions
  await lua.doString(`
    -- Remove access to the OS library (filesystem, process execution)
    os = nil

    -- Remove access to the IO library (file reading/writing)
    io = nil

    -- Remove the ability to load external files
    dofile = nil
    loadfile = nil

    -- Remove the debug library (can be used to escape the sandbox)
    debug = nil

    -- Remove the ability to load C modules
    package = nil
    require = nil

    -- Remove raw access to the global table modification
    rawset = nil
    rawget = nil

    -- Keep only safe standard libraries:
    -- math, string, table, utf8, tonumber, tostring,
    -- pairs, ipairs, next, select, type, error, pcall, xpcall
  `);

  return lua;
}

